mapper.select:
SELECT TIME as time, CPU_RATE as cpuRate, CPU_READY as cpuReady, MEMORY as memory, DOMAIN_ID as domainId, HOST_ID as hostId, HOST_POOL_ID as hostpoolId,
CLUSTER_ID as clusterId, OP_GROUP_CODE as operatorGroupCode, OP_GROUP_ID as operatorGroupId, CPU_USAGE_MHZ as cpuUsageMhz FROM TBL_DOMAIN_CPU_DETAIL
WHERE TIME BETWEEN ${startTime} AND ${endTime}

    AND DOMAIN_ID=${domainId}


    AND CLUSTER_ID in (${clusterIds})


    AND HOST_ID in (${hostIds})


    AND DOMAIN_ID in (${vmIds})


    AND OP_GROUP_CODE LIKE #{operatorGroupCode}


    ORDER BY ${sortField} ASC


    ORDER BY ${sortField} DESC

SELECT DOMAIN_ID as domainId, domain.uuid as  uuid, domain.title as title, domain.host_id as hostId,


        ROUND(AVG(CPU_RATE),2) as cpuRate


        ROUND(AVG(CPU_USAGE_MHZ),2) as cpuUsageMhz


        ROUND(AVG(MEMORY),2) as memory


FROM TBL_DOMAIN_CPU_DETAIL cpuDetail ,
${@com.h3c.h3cloud.performance.monitor.service.mapper.base.clickhouseMapperConstant@TBL_DOMAIN} domain WHERE cpuDetail.DOMAIN_ID = domain.id AND domain.enable = 1
AND cpuDetail.TIME BETWEEN ${startTime} AND ${endTime}

    AND HOST_POOL_ID =${hostPoolId}


    AND CLUSTER_ID =${clusterId}


    AND HOST_ID =${hostId}


    AND CLUSTER_ID in (${clusterIds})


    AND HOST_ID in (${hostIds})


    AND DOMAIN_ID in (${vmIds})


    AND LOCATE(#{manageExistVm}, domain.metdata)


    AND OP_GROUP_CODE LIKE #{operatorGroupCode}

GROUP BY cpuDetail.DOMAIN_ID, domain.uuid, domain.title, domain.host_id having MAX(cpuDetail.TIME) > ${endTime} -241


        ORDER BY cpuRate DESC


        ORDER BY cpuUsageMhz DESC


        ORDER BY memory DESC



    LIMIT ${limit}

SELECT ROUND(AVG(CPU_RATE),2) as cpuRate, ROUND(AVG(MEMORY),2) as memory, DOMAIN_ID as domainId FROM TBL_DOMAIN_CPU_DETAIL
WHERE TIME BETWEEN ${startTime} AND ${endTime}

    AND DOMAIN_ID = ${domainId}


    AND HOST_POOL_ID =${hostPoolId}


    AND OP_GROUP_CODE LIKE #{operatorGroupCode}


    AND DOMAIN_ID in (${vmIds})

GROUP BY DOMAIN_ID

SELECT MAX(CPU_RATE) as cpuRate, MAX(MEMORY) as memory, DOMAIN_ID as domainId FROM TBL_DOMAIN_CPU_DETAIL
WHERE TIME BETWEEN ${startTime} AND ${endTime}

     AND DOMAIN_ID = ${domainId}


     AND HOST_POOL_ID =${hostPoolId}


     AND DOMAIN_ID in (${vmIds})


     AND OP_GROUP_CODE LIKE #{operatorGroupCode}

 GROUP BY DOMAIN_ID

SELECT C.TIME as time, C.CPU_RATE as cpuRate, C.MEMORY as memory, C.DOMAIN_ID as domainId, C.CPU_USAGE_MHZ as cpuUsageMhz from TBL_DOMAIN_CPU_DETAIL C  WHERE C.TIME=( SELECT MAX(TIME)-${duration} FROM TBL_DOMAIN_CPU_DETAIL)

     AND C.HOST_POOL_ID =${hostPoolId}


     AND C.HOST_ID =${hostId}


     AND C.DOMAIN_ID = ${domainId}


     AND C.CLUSTER_ID =${clusterId}


     AND C.DOMAIN_ID in (${vmIds})


     AND C.OP_GROUP_CODE LIKE #{operatorGroupCode}


     ORDER BY ${sortField} ASC


     ORDER BY ${sortField} DESC



         LIMIT ${limit}


         LIMIT ${offset},${limit}

SELECT FLOW.DOMAIN_ID as domainId,


        ROUND(AVG(FLOW.CPU_RATE),2) as avgCpuRate


        ROUND(AVG(FLOW.MEMORY),2) as avgMemRate


FROM  ${@com.h3c.h3cloud.performance.monitor.service.mapper.base.clickhouseMapperConstant@TBL_DOMAIN} TD,
TBL_DOMAIN_CPU_DETAIL FLOW  WHERE TD.id = FLOW.DOMAIN_ID AND TIME BETWEEN ${startTime} AND ${endTime}

    AND FLOW.HOST_POOL_ID =${hostPoolId}


    AND FLOW.CLUSTER_ID =${clusterId}


    AND FLOW.HOST_ID =${hostId}


    AND FLOW.OP_GROUP_CODE LIKE #{operatorGroupCode}

GROUP BY FLOW.DOMAIN_ID


        ORDER BY avgCpuRate DESC


        ORDER BY avgMemRate DESC



    LIMIT ${limit}

SELECT DOMAIN_ID as domainId, ROUND(AVG(CPU_RATE),2) as avgCpuRate , MAX(CPU_RATE) as maxCpuRate, MIN(CPU_RATE) as minCpuRate, ROUND(AVG(MEMORY),2) as avgMemRate , MAX(MEMORY) as maxMemRate, MIN(MEMORY) as minMemRate FROM TBL_DOMAIN_CPU_DETAIL detail WHERE TIME BETWEEN ${startTime} AND ${endTime}
AND DOMAIN_ID = ${domainId}
AND DOMAIN_ID in (${vmIds})
GROUP BY DOMAIN_ID

SELECT ROUND(AVG(CPU_RATE),2) as cpuRate,ROUND(AVG(MEMORY),2) as memory FROM TBL_DOMAIN_CPU_DETAIL WHERE DOMAIN_ID = ${domainId}
AND TIME >= (SELECT MAX(TIME) FROM TBL_DOMAIN_CPU_DETAIL WHERE DOMAIN_ID = ${domainId}) -${duration}
GROUP BY DOMAIN_ID
